-- Enrichment marathon batch: Coupler (Coupler.io), Coveralls (coveralls.io), Cozy Cloud, CPU-X, CPU-Z, Cradlepoint, CraftMyPDF, CrateDB

-- ── Coupler (Coupler.io) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Coupler.io is a no-code data integration and automation platform that connects business apps, databases, and files to spreadsheets, BI tools, and data warehouses. It lets non-technical users build scheduled data flows called Importers that pull data from over 400 sources into destinations like Google Sheets, Excel, BigQuery, and Looker Studio. The platform targets analysts, marketers, agencies, and operations teams that need recurring reporting without engineering support.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, tiered monthly or annual subscription priced by number of connected accounts, data destinations, refresh frequency, and users, with annual billing discounted versus monthly$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans start around 24 USD per month billed annually (32 USD per month billed monthly) for the Starter plan$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Danbury, Connecticut, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Coupler.io Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Coupler.io syncs data from 400+ sources into Google Sheets, Excel, BI tools, and warehouses. Compare pricing, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Coupler.io is a no-code data integration, automation, and reporting platform founded in 2014 and headquartered in Danbury, Connecticut, United States. It is built for analysts, marketers, agencies, and operations teams that need to move data out of business applications and into spreadsheets, BI dashboards, or data warehouses without writing code or maintaining custom scripts. The core workflow revolves around an Importer: a user selects a data source from a library of more than 400 connectors, covering categories like CRM (HubSpot, Pipedrive, Salesforce), advertising and analytics (Google Analytics, Google Ads, Facebook Ads), accounting (QuickBooks, Xero), e-commerce (Shopify), and project management (Jira, Asana, Airtable), then selects a destination such as Google Sheets, Microsoft Excel, BigQuery, Snowflake, Amazon Redshift, Looker Studio, Power BI, or Tableau. The Importer can be scheduled to refresh automatically on intervals ranging from every 15 minutes on higher-tier plans to daily on lower tiers, which keeps recurring reports current without manual exports. Coupler.io also provides prebuilt dashboard templates for common reporting needs such as marketing performance, sales pipeline tracking, and finance consolidation, reducing setup time for non-technical users. Pricing follows a freemium, tiered subscription model. The Free plan supports one connected account, one destination, manual refresh, and a 100-row limit per run. The Starter plan (roughly 24 to 32 USD per month depending on billing cycle) adds three accounts, one destination, and daily refresh. The Active plan (roughly 99 to 132 USD per month) scales to 15 accounts, three destinations, unlimited data volume, unlimited users, and data transformation features. The Pro plan (roughly 199 to 259 USD per month) extends to 50 accounts, unlimited destinations, hourly refresh, team workspaces, automation features, and a dedicated account manager. An Agency and Enterprise tier offers custom pricing with 15-minute refresh, personal account management, priority support, and enterprise SLAs. Annual billing typically saves about 25 percent compared with paying monthly, and additional accounts beyond a plan's included quota can be purchased incrementally. Because pricing scales primarily with the number of source-to-destination connections rather than raw data volume, costs can increase quickly for organizations running many parallel data flows, which is a recurring theme in independent reviews and pricing comparisons. Coupler.io's key differentiators are its no-code configuration (no SQL or scripting required for standard flows), its spreadsheet-first orientation for teams that live in Google Sheets and Excel, its broad connector library spanning marketing, sales, finance, and operations tools, and its built-in data transformation layer available from the Active plan upward, which allows filtering, joining, and reshaping data before it reaches its destination. Through 2026 the vendor has been layering in AI-assisted capabilities, including natural-language creation of data flows and AI-driven analysis of synced datasets. Coupler.io is generally positioned against tools like Fivetran, Airbyte, Supermetrics, and Coefficient, and is typically chosen by small and mid-size teams that want an affordable, spreadsheet-native alternative to heavier enterprise data pipeline tools rather than large-scale data engineering platforms. As a hosted SaaS product, it requires no customer-managed infrastructure; all connections, schedules, and transformations are configured through its web interface.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '761c6882-76cc-4899-8894-6e19fcd03196';

