-- ── CPU-Z ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CPU-Z is a free system information and diagnostic utility for Windows, developed by the French company CPUID, that reports detailed specifications for a computer's processor, motherboard, memory, and graphics card. It provides real-time measurements of core clock speeds and memory frequency, and includes a hardware validation feature that generates a shareable link summarizing a system's specs. CPU-Z is widely used by PC enthusiasts, overclockers, and buyers verifying hardware authenticity.$q$, short_description),
  pricing_model = COALESCE($q$Free freeware, no paid tiers or subscriptions$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Dunkerque, France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CPU-Z Review 2026: Free Windows Hardware Info Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$CPU-Z by CPUID reports CPU, motherboard, memory, and GPU specs on Windows. See features, validation tool, pros, cons, and FAQs for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CPU-Z is a free system information and diagnostic utility for Windows created by Franck Delattre, whose work later formed the basis of CPUID, a software company he founded in 2007 and headquartered in Dunkerque, France. CPU-Z itself predates the formal company, with its first versions released in the early 2000s as a lightweight tool for reporting detailed hardware specifications, and it has since become one of the most widely used free diagnostic utilities in the PC enthusiast and overclocking communities. The application gathers and displays information across several categories, organized into tabs within its interface: the CPU tab shows processor name and number, codename, manufacturing process, package type, core voltage, and multiple levels of cache; the Mainboard tab reports motherboard manufacturer, model, and chipset, along with BIOS details; the Memory and SPD tabs show installed RAM type, total size, timings, and per-module specifications read directly from each memory stick's Serial Presence Detect (SPD) data; and the Graphics tab reports the installed GPU model and specifications. Beyond static specifications, CPU-Z provides real-time monitoring of each CPU core's internal operating frequency and current memory frequency, which is useful for verifying that overclocking settings are being applied correctly or that a system is running at its rated speeds. A widely used feature is CPU-Z's hardware validation tool, which generates a unique, shareable web link summarizing a system's full hardware configuration at the moment of validation; this is commonly used to prove a specific hardware configuration for online forum discussions, benchmark submissions, hardware trading or resale listings, or overclocking competition verification. CPU-Z is distributed entirely free of charge as freeware, with no premium tier, subscription, or paid unlock, and CPUID's revenue instead comes from other commercial and enterprise-focused products in its lineup, such as PC Wizard, HWMonitor, and enterprise hardware inventory tools. CPU-Z supports a broad range of Windows versions, from older releases such as Windows XP and Vista through Windows 7, 8, 10, and full support for Windows 11, and both 32-bit and 64-bit editions are available for download. CPUID also publishes a CPU-Z mobile app for Android that reports equivalent hardware information for smartphones and tablets, extending the CPU-Z brand beyond desktop PCs. Because CPU-Z reads hardware information directly rather than relying on manufacturer marketing specifications, it is frequently used to verify that a purchased or pre-built PC actually contains the components it was advertised with, to confirm memory is running at its rated speed and timings, and to diagnose potential hardware issues such as underperforming components. As a long-standing, narrowly scoped freeware tool rather than a broad system utility suite, CPU-Z's popularity rests on its accuracy, minimal footprint, and status as a de facto standard reference tool that is frequently bundled or recommended alongside benchmarking software in reviews, buying guides, and enthusiast communities.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ba7da5aa-1683-4bf9-a259-63591d303e29';

