-- ── Cradlepoint ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cradlepoint is a provider of cellular and 5G wireless edge networking hardware and cloud-managed software, offering routers and adapters for enterprise branch, mobile, and IoT connectivity. Founded in 2006 and headquartered in Boise, Idaho, the company was acquired by Ericsson in 2020 for an enterprise value of about 1.1 billion USD and now operates as part of Ericsson's enterprise business. Its NetCloud platform combines purpose-built routers with cloud management, security, and SD-WAN capabilities.$q$, short_description),
  pricing_model = COALESCE($q$Subscription-based NetCloud service plans bundled with hardware, sold primarily through partners and resellers with quote-based enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$Reseller-quoted subscription and hardware pricing; publicly listed NetCloud plan pricing has ranged from roughly 28.50 USD to over 1,000 USD depending on plan tier, term length, and hardware$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$500-1000 employees (as a subsidiary of Ericsson)$q$, company_size),
  headquarters = COALESCE($q$Boise, Idaho, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cradlepoint Review 2026: 5G Routers, NetCloud and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Cradlepoint (Ericsson) provides 5G wireless edge routers and NetCloud cloud management. See features, plans, pros, cons, and FAQs for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cradlepoint is a wireless wide area network (WWAN) edge networking company founded in 2006 and headquartered in Boise, Idaho, United States, with additional development centers in Silicon Valley and India and international offices in the United Kingdom and Australia. The company was acquired by Ericsson on November 1, 2020, in a deal valuing Cradlepoint at an enterprise value of approximately 1.1 billion USD, and it now operates as part of Ericsson's enterprise wireless solutions business, marketed under names including Ericsson Cradlepoint and NetCloud by Ericsson. Cradlepoint's core business is cellular and 5G wireless edge networking: purpose-built routers, adapters, and gateways that use 4G LTE and 5G cellular connections as primary or backup wide area network links for branch offices, vehicles, IoT deployments, and temporary or pop-up locations, paired with a cloud-based management and orchestration platform called NetCloud. NetCloud Service centralizes device provisioning, configuration, monitoring, security policy enforcement, and lifecycle management for Cradlepoint's hardware fleet, and is organized into several product lines aligned to use case: NetCloud for Enterprise Branch, which supports advanced routing, dynamic path selection, SD-WAN integration, and Zero Trust-style security segmentation for multi-site branch networks using hardware like the E300, E400, and E3000 series routers; NetCloud for Small Branch, which offers simplified, template-driven configuration and basic firewalling for lower-complexity sites with faster deployment; NetCloud for Mobile, which targets in-vehicle and field-service connectivity using ruggedized routers designed for public safety, transportation, and utility fleets; and NetCloud for IoT, optimized for connecting distributed sensors and devices to the cloud with an emphasis on security and reliability at scale. NetCloud plans are typically sold as multi-year subscriptions bundled with hardware, support, and warranty coverage, and pricing is largely quote-based through Cradlepoint's partner and reseller network rather than published as flat public list prices; publicly available reseller pricing shows a wide range depending on plan tier, hardware model, and subscription term, spanning from roughly the high 20s to over 1,000 USD per unit depending on configuration. Higher NetCloud Advanced tiers add features such as application traffic analytics, application-aware firewalling, and URL content filtering on top of base connectivity and management. Cradlepoint has also worked with Ericsson on network slicing proof-of-concept demonstrations aimed at showing how 5G network slicing can unlock differentiated connectivity tiers for enterprise customers, reflecting the strategic rationale behind Ericsson's acquisition: combining Ericsson's mobile network infrastructure and 5G expertise with Cradlepoint's enterprise-facing edge hardware and cloud management software. Cradlepoint is generally positioned as a leader in the cloud-delivered 4G and 5G wireless WAN edge category, competing with vendors such as Cisco Meraki, Peplink, and Sierra Wireless, and is most commonly selected by organizations that need reliable, centrally managed cellular connectivity for distributed branch locations, mobile workforces, or IoT deployments where wired broadband is unavailable, unreliable, or needed only as a backup link.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fe1086f4-8a3a-47da-98c7-f45cde6555a4';

