-- ── CraftMyPDF ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CraftMyPDF is a cloud-based API and drag-and-drop template editor for generating PDF documents and images dynamically from data, without requiring code for template design. It supports both synchronous and asynchronous generation at scale, interactive fillable PDF forms, and regional endpoints for data residency. CraftMyPDF is built for developers and no-code teams automating document workflows such as invoices, contracts, and reports.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, tiered monthly or annual subscription priced by number of PDFs/images generated and templates allowed, with annual billing offering a discount$q$, pricing_model),
  starting_price = COALESCE($q$Free plan with 50 PDFs/images per month; paid plans start at 29 USD per month (Lite plan)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Singapore$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CraftMyPDF Review 2026: PDF Generation API and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$CraftMyPDF turns templates into PDFs via API. See 2026 pricing plans, features, integrations, pros, cons, and FAQs for document automation.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CraftMyPDF is a cloud-based PDF generation API and template design platform founded in 2021 by Jacky Tan and headquartered in Singapore. It was built to let developers and no-code teams turn structured data into polished PDF documents or images at scale, without needing to build and maintain custom PDF rendering infrastructure. The platform is centered on a drag-and-drop template editor that lets users design document layouts visually, placing text fields, images, tables, and other elements onto a canvas, then binding those elements to dynamic data fields that get populated automatically when a document is generated through the API. Templates support rich formatting, including custom fonts, and built-in expressions for formatting dates, currencies, numbers, and text, as well as the ability to extend templates with custom JavaScript functions for more advanced logic. Beyond static documents, CraftMyPDF supports interactive fillable PDF forms, letting designers add components such as text fields, checkboxes, dropdown menus, radio buttons, and digital signature fields directly in the same drag-and-drop editor, which is useful for generating contracts, applications, and other documents that end users need to fill in after generation. The core product is accessed primarily through a REST API, and CraftMyPDF also offers native integrations with Zapier, Make (formerly Integromat), Bubble, and Coda, allowing non-developers to connect PDF generation into existing automation workflows without writing custom API calls. For generation performance and data residency, CraftMyPDF offers regional endpoints in the United States, European Union, Singapore, and Australia, letting customers keep document processing closer to their users or within specific regulatory jurisdictions. On the security and compliance side, CraftMyPDF has completed a SOC 2 Type II audit, which is intended to give business customers confidence in the platform's security, reliability, and operational controls, and it offers a Data Processing Agreement starting from its Lite plan for customers with data protection requirements. Pricing follows a freemium, usage-based tiered model measured primarily in number of PDFs or images generated per month and number of templates allowed. The Free plan includes 50 PDFs or images and 3 templates per month with no credit card required. The Lite plan is 29 USD per month for 1,200 PDFs or images and 6 templates, and includes DPA availability. The Plus plan is 49 USD per month for 3,000 PDFs or images and 15 templates, adding live chat support. The Professional plan is 99 USD per month for 12,000 PDFs or images and 50 templates, and introduces team collaboration, the ability to bring your own cloud storage, and PDF password protection. The Premium plan is 299 USD per month for 40,000 PDFs or images and 1,000 templates with priority support across email, live chat, and video calls. The Business plan is 499 USD per month for 150,000 PDFs or images and 10,000 templates, aimed at large-scale document automation operations. Annual billing is available across paid tiers and can save up to roughly 17 percent compared to monthly billing. CraftMyPDF is typically compared to competitors such as PDF Generator API, PDFMonkey, and APITemplate.io, and is generally chosen by SaaS companies, agencies, and internal engineering teams that need to generate invoices, contracts, reports, certificates, or other data-driven documents automatically as part of a larger product or workflow.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c784f807-986f-42ed-bef7-f3172bf29eb6';

